          CREATE View [SSRS].[JuniorLeague_Division_EndofSeason]  as    SELECT [League_ID]        ,REPLACE(REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' '),'+',' plus') AS Name         ,[Division_Of_Fixture]        ,[No Result]        ,[Year_Of_Fixture]        ,SUM([Abandoned]   )[Abandoned]        ,SUM([Cancelled]   )[Cancelled]        ,SUM([Conceded]   )[Conceded]        ,SUM([InProgress]   )[InProgress]        ,SUM([Win]    )[Win]    FROM [SSRS].[JuniorLeagues_Division_STD_2021]    Group by [League_ID]        ,[Name]        ,[Division_Of_Fixture]        ,[No Result]        ,[Year_Of_Fixture]    